```properties
# nginx -p /opt/vllm_cluster/nginx -c /opt/vllm_cluster/nginx/nginx.vllm.conf
worker_processes auto;
pid logs/nginx.pid;
error_log logs/error.log info;
events {
  worker_connections 8192;
  multi_accept on;
}
http {
  include /etc/nginx/mime.types;
  default_type  application/octet-stream;
  access_log    logs/access.log;
  sendfile on;
  tcp_nopush on;
  tcp_nodelay on;
  keepalive_timeout  65;
  types_hash_max_size 2048;
  map $http_upgrade $connection_upgrade {
    default upgrade;
    ''      close;
  }
  upstream vllm_pool {
    # 修改处：现在是 4 个实例 (72B TP=2)
    # 对应 bash 脚本中的 i=0,1,2,3 -> 8000, 8002, 8004, 8006
    server 127.0.0.1:8000 max_fails=3 fail_timeout=10s;
    server 127.0.0.1:8002 max_fails=3 fail_timeout=10s;
    server 127.0.0.1:8004 max_fails=3 fail_timeout=10s;
    server 127.0.0.1:8006 max_fails=3 fail_timeout=10s;

    # 删除了原来的 8008, 8010, 8012, 8014，因为那些端口现在没有服务在跑了
  }
  server {
    listen 18080;
    # ===== vLLM 的 /v1/* 入口 =====
    location /v1/ {
      proxy_pass http://vllm_pool;
      proxy_http_version 1.1;
      proxy_set_header Connection "";
      client_max_body_size 64m;
      proxy_connect_timeout 60s;
      proxy_read_timeout 300s;
      proxy_send_timeout 300s;
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
      proxy_set_header X-Forwarded-Proto $scheme;
    }
    # ===== 转发到 Flask 7871 =====
    location /7871/ {
      client_max_body_size 64m;
      client_body_timeout 120s;
      proxy_request_buffering off;
      proxy_connect_timeout 60s;
      proxy_send_timeout 600s;
      proxy_read_timeout 600s;
      send_timeout 600s;
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
      proxy_set_header X-Forwarded-Proto $scheme;
      proxy_pass http://127.0.0.1:7871/;
    }
    # 健康检查
    location = /healthz {
      # 注意：如果后端任意一个挂了，Nginx默认会尝试轮询下一个
      proxy_pass http://vllm_pool/v1/models;
      proxy_read_timeout 10s;
    }
    location = / { default_type text/plain; return 200 "vLLM gateway is up.\nUse /v1/* endpoints.\n"; }
    location = /favicon.ico { return 204; }
  }
}
